import React from 'react';
import {
    Dialog,
    DialogTitle,
    DialogContent,
    DialogContentText,
    DialogActions,
    Button,
    Box,
    FormLabel,
    RadioGroup,
    FormControlLabel,
    Radio,
    IconButton,
    Typography
} from '@mui/material';
import AddIcon from '@mui/icons-material/Add';
import RemoveIcon from '@mui/icons-material/Remove';
import { useBodyScrollLock } from '@/hooks/useBodyScrollLock';

export type EventActionType = 'register' | 'checkin' | 'cancel' | 'update' | 'delete';

interface EventActionDialogProps {
    open: boolean;
    actionType: EventActionType;
    userName: string;
    eventTitle?: string; // Optional: for registration from event card
    onClose: () => void;
    onConfirm: (foodPreference: string, count: number) => void;
    
    // Event configuration
    isFoodEnabled?: boolean;
    isAccompanyEnabled?: boolean;
    foodOptions?: string[];
    
    // Initial values (for pre-population)
    initialFoodPreference?: string;
    initialCount?: number;
    
    // Validation
    isLoading?: boolean;
}

export const EventActionDialog: React.FC<EventActionDialogProps> = ({
    open,
    actionType,
    userName,
    eventTitle,
    onClose,
    onConfirm,
    isFoodEnabled = false,
    isAccompanyEnabled = false,
    foodOptions = [],
    initialFoodPreference = '',
    initialCount = 1,
    isLoading = false
}) => {
    const minCount = 1;
    const maxCount = isAccompanyEnabled ? 100 : 1;

    const [foodPreference, setFoodPreference] = React.useState<string>(initialFoodPreference);
    const [count, setCount] = React.useState<number>(initialCount);

    useBodyScrollLock(open);

    // Reset state when dialog opens
    React.useEffect(() => {
        if (open) {
            setFoodPreference(initialFoodPreference);
            setCount(initialCount);
        }
    }, [open, initialFoodPreference, initialCount]);

    // Clear food preference when headcount becomes 0
    React.useEffect(() => {
        if (count === 0) {
            setFoodPreference('');
        }
    }, [count]);

    const handleConfirm = () => {
        onConfirm(foodPreference, count);
    };

    const handleCountIncrease = () => {
        setCount(Math.min(maxCount, count + 1));
    };

    const handleCountDecrease = () => {
        setCount(Math.max(minCount, count - 1));
    };

    // Determine validation
    const isValid = React.useMemo(() => {
        if (actionType === 'cancel' || actionType === 'delete') {
            return true; // No validation needed for cancel
        }
        
        // Check headcount restrictions based on isAccompanyEnabled
        if (count < minCount || count > maxCount) {
            return false;
        }
        
        // Check food validation - only required when headcount > 0 and food is enabled
        if (isFoodEnabled && foodOptions.length > 0 && count > 0 && !foodPreference) {
            return false;
        }
        
        return true;
    }, [actionType, isFoodEnabled, foodOptions, count, foodPreference, maxCount]);

    // Get dialog content based on action type
    const getDialogContent = () => {
        switch (actionType) {
            case 'register':
                return {
                    title: 'Registration Details',
                    description: eventTitle 
                        ? `Register for ${eventTitle}.`
                        : `Register ${userName} for the event.`,
                    confirmText: 'Register',
                    confirmColor: 'primary' as const
                };
            case 'checkin':
                return {
                    title: 'Check-In Details',
                    description: `Check-in ${userName} for the event.`,
                    confirmText: 'Check In',
                    confirmColor: 'success' as const
                };
            case 'cancel':
                return {
                    title: 'Cancel Registration',
                    description: `Are you sure you want to cancel the registration for ${userName}? This action cannot be undone.`,
                    confirmText: 'Confirm',
                    confirmColor: 'error' as const
                };
            case 'delete':
                return {
                    title: 'Delete Attendee',
                    description: `Permanently delete the attendee record for ${userName}? This will remove all registration information and cannot be undone.`,
                    confirmText: 'Delete',
                    confirmColor: 'error' as const
                };
            case 'update':
                return {
                    title: 'Update Registration',
                    description: `Update registration details for ${userName}.`,
                    confirmText: 'Update',
                    confirmColor: 'primary' as const
                };
        }
    };

    const content = getDialogContent();

    return (
        <Dialog
            open={open}
            onClose={onClose}
            aria-labelledby="event-action-dialog-title"
            maxWidth="sm"
            fullWidth
        >
            <DialogTitle id="event-action-dialog-title">
                {content.title}
            </DialogTitle>
            <DialogContent>
                <DialogContentText sx={{ mb: actionType !== 'cancel' && actionType !== 'delete' ? 2 : 0 }}>
                    {content.description.split(userName).map((part, index, array) => (
                        index < array.length - 1 ? (
                            <React.Fragment key={index}>
                                {part}
                                <strong>{userName}</strong>
                            </React.Fragment>
                        ) : part
                    ))}
                </DialogContentText>

                {/* Only show form fields when we need to capture extra details */}
                {actionType !== 'cancel' && actionType !== 'delete' && (
                    <Box sx={{ pt: 1 }}>
                        {/* Head Count - Always shown, but with different limits based on isAccompanyEnabled */}
                        <Box sx={{ mb: 3 }}>
                            <FormLabel component="legend" sx={{ fontWeight: 600, mb: 1 }}>
                                Head Count *
                            </FormLabel>
                            <Box sx={{ display: 'flex', alignItems: 'center', gap: 2 }}>
                                <IconButton
                                    size="small"
                                    onClick={handleCountDecrease}
                                    disabled={count <= minCount}
                                    aria-label="Decrease count"
                                >
                                    <RemoveIcon fontSize="small" />
                                </IconButton>
                                <Typography variant="h6" sx={{ minWidth: '40px', textAlign: 'center' }}>
                                    {count}
                                </Typography>
                                <IconButton
                                    size="small"
                                    onClick={handleCountIncrease}
                                    disabled={count >= maxCount}
                                    aria-label="Increase count"
                                >
                                    <AddIcon fontSize="small" />
                                </IconButton>
                            </Box>
                            {!isAccompanyEnabled && (
                                <Typography variant="caption" color="text.secondary" sx={{ display: 'block', mt: 0.5 }}>
                                    Limited to 1 attendee
                                </Typography>
                            )}
                        </Box>

                        {/* Food Preference - Only shown when headcount > 0 */}
                        {isFoodEnabled && foodOptions.length > 0 && count > 0 && (
                            <Box>
                                <FormLabel component="legend" sx={{ fontWeight: 600, mb: 1 }} required>
                                    Food Preference *
                                </FormLabel>
                                <RadioGroup
                                    value={foodPreference}
                                    onChange={(e) => setFoodPreference(e.target.value)}
                                >
                                    {foodOptions.map((option: string) => (
                                        <FormControlLabel
                                            key={option.trim()}
                                            value={option.trim()}
                                            control={<Radio />}
                                            label={option.trim()}
                                        />
                                    ))}
                                </RadioGroup>
                            </Box>
                        )}
                    </Box>
                )}
            </DialogContent>
            <DialogActions>
                <Button onClick={onClose} color="inherit" disabled={isLoading}>
                    Cancel
                </Button>
                <Button
                    onClick={handleConfirm}
                    color={content.confirmColor}
                    variant="contained"
                    autoFocus
                    disabled={!isValid || isLoading}
                >
                    {content.confirmText}
                </Button>
            </DialogActions>
        </Dialog>
    );
};
